UPDATE t_p28211681_photo_secure_web.legal_documents
SET content = replace(
  content,
  '<p>5.4. Данные учётной записи при авторизации через сторонние сервисы (Google, ВКонтакте, Телеграмм): идентификатор пользователя, имя, адрес электронной почты, изображение профиля.</p>',
  '<p>5.4. Данные учётной записи Пользователя, передаваемые при входе (авторизации) через сторонние сервисы — Яндекс, ВКонтакте (VK ID), Google, Телеграмм. С согласия Пользователя, подтверждаемого на экране предоставления разрешений соответствующего сервиса, Оператор получает: уникальный идентификатор учётной записи в сервисе, фамилию, имя (логин), адрес электронной почты, портрет (изображение профиля), пол, а при авторизации через Яндекс и ВКонтакте — также номер телефона. Состав передаваемых данных определяется настройками соответствующего сервиса; данные передаются из стороннего сервиса Оператору и обрабатываются в соответствии с настоящей Политикой и правилами этого сервиса.</p>'
),
version = version + 1,
updated_at = CURRENT_TIMESTAMP
WHERE slug = 'privacy-policy';